const date = new Date();
const jstOffset = 9 * 60;
const jstDate = new Date(date.getTime() + (jstOffset + date.getTimezoneOffset()) * 60000);

const yyyy = jstDate.getFullYear();
const mm = String(jstDate.getMonth() + 1).padStart(2, '0');
const dd = String(jstDate.getDate()).padStart(2, '0');
const datePrefix = `H${yyyy}${mm}${dd}`;

// 前ノードから取得した「受付ID一覧」を取得
const existingIds = $input.all().map(item => item.json['受付ID'] || '').filter(id => id.startsWith(datePrefix));

// 当日の最大連番を計算
let maxSeq = 0;
existingIds.forEach(id => {
  const match = id.match(/-(\d{3})$/);
  if (match) {
    const seq = parseInt(match[1], 10);
    if (seq > maxSeq) maxSeq = seq;
  }
});

const newSeq = String(maxSeq + 1).padStart(3, '0');
const receivedId = `${datePrefix}-${newSeq}`;

// 受信したペイロードと結合
const payload = $('Webhook').first().json.body;

return [{
  json: {
    receivedId: receivedId,
    receivedAt: jstDate.toISOString().replace('T', ' ').substring(0, 19),
    payload: payload
  }
}];

const receivedId = $input.first().json.receivedId;
const payload = $input.first().json.payload;
const common = payload.commonSettings;
const properties = payload.properties;

// 各物件の最終値を計算
const rows = properties.map(p => {
  const ov = p.override || {};

  // override値が空でなければ採用、空なら共通設定を採用
  const finalValue = (overrideVal, commonVal) => {
    if (overrideVal && overrideVal !== '') return overrideVal;
    return commonVal;
  };

  return {
    受付ID: receivedId,
    物件連番: p.index,
    施設名: p.name,
    部屋番号: p.room,
    住所: p.address,
    業態: p.businessTypeLabel,
    鍵の種類: p.keyTypeLabel,
    鍵の詳細: p.keyTypeDetail,
    鍵の暗証番号: p.passcode,
    保健所立ち会い状況: p.healthInspectionLabel,
    保健所立ち会い日付: p.healthInspectionDate,
    届出番号状況: p.registrationLabel,
    届出番号: p.registrationNumber,
    発行予定日: p.registrationDate,
    'チェックイン時間(最終値)': finalValue(ov.checkinTime, common.checkinTime),
    'チェックアウト時間(最終値)': finalValue(ov.checkoutTime, common.checkoutTime),
    'アーリーチェックイン(最終値)': finalValue(ov.earlyCheckinLabel, common.earlyCheckinLabel),
    'アーリー開始時刻(最終値)': finalValue(ov.earlyCheckinTime, common.earlyCheckinTime),
    'レイトチェックアウト(最終値)': finalValue(ov.lateCheckoutLabel, common.lateCheckoutLabel),
    'レイト最終時刻(最終値)': finalValue(ov.lateCheckoutTime, common.lateCheckoutTime),
    '荷物預かり(最終値)': finalValue(ov.luggageStorageLabel, common.luggageStorageLabel),
    '荷物預かり開始時刻(最終値)': finalValue(ov.luggageStorageTime, common.luggageStorageTime),
    'タブレット設置場所(最終値)': finalValue(p.tabletLocationLabel, common.tabletLocationLabel),
    '鍵の解錠方法(最終値)': finalValue(ov.keyAccess, common.keyAccess),
    '自動メッセージ送信タイミング(最終値)': finalValue(ov.messageTimingLabel, common.messageTimingLabel),
    '共通設定からの上書きあり': p.hasOverride ? 'TRUE' : 'FALSE'
  };
});

// 物件数分のアイテムとして返す（n8n側で1行ずつスプレッドシートに追記される）
return rows.map(row => ({ json: row }));

// 元の Webhook ペイロードから情報を取得
// 注意: 前段で物件詳細を追記したアイテムが複数あるため、Webhookノードを参照する
const payload = $('Webhook').first().json.body;
const receivedId = $('Code: 受付ID生成').first().json.receivedId;
const properties = payload.properties;
const common = payload.commonSettings;
const tasks = [];

const formatList = (props) => props.map(p => `物件${p.index}「${p.name}」`).join('、');

// 1. 特区民泊
const toku = properties.filter(p => p.businessType === 'toku');
if (toku.length > 0) {
  tasks.push(`【定期借家契約書の作成・送付】特区民泊の物件 (${formatList(toku)}) は定期借家契約書の作成が必要です。作成後、PDF等で customer@bizpato.com までお送りください。`);
}

// 2. Beds24メール追加
const hasBeds24Op = payload.contractor.contractedOptions.includes('beds24');
if (common.beds24 === 'contracted' && !hasBeds24Op) {
  tasks.push(`【Beds24認証用メールアドレスの追加】Beds24のログイン認証用メールアドレスに customer@bizpato.com を追加してください。追加方法: Beds24サポート(https://co-reception.com/support-ticket/)に依頼。`);
}

// 3. Beds24未契約
if (common.beds24 === 'planned') {
  tasks.push(`【Beds24契約完了の連絡】Beds24のご契約が完了しましたら、customer@bizpato.com までご連絡ください。`);
}

// 4. RemoteLOCK未契約
if (common.remotelock === 'planned') {
  tasks.push(`【RemoteLOCK契約完了の連絡】RemoteLOCKのご契約が完了しましたら、customer@bizpato.com までご連絡ください。`);
}

// 5. 保健所立ち会い予定
const plannedHealth = properties.filter(p => p.healthInspection === 'planned');
if (plannedHealth.length > 0) {
  tasks.push(`【保健所立ち会い完了の連絡】対象物件 (${formatList(plannedHealth)}) の保健所立ち会い完了後、customer@bizpato.com までご連絡ください。`);
}

// 6. 届出番号発行予定
const plannedReg = properties.filter(p => p.registration === 'planned');
if (plannedReg.length > 0) {
  tasks.push(`【届出番号発行後の連絡】対象物件 (${formatList(plannedReg)}) の届出番号発行後、番号を customer@bizpato.com までご連絡ください。`);
}

// 7. ランダム暗証番号
const random = properties.filter(p => p.keyType === 'other_smartlock_random');
if (random.length > 0) {
  tasks.push(`【ゲスト様への暗証番号の個別通知】対象物件 (${formatList(random)}) はランダム暗証番号のスマートロックです。チェックイン前にゲスト様へ暗証番号を個別にお伝えください。`);
}

return [{
  json: {
    receivedId: receivedId,
    payload: payload,
    tasks: tasks,
    tasksText: tasks.length > 0
      ? tasks.map((t, i) => `${i + 1}. ${t}`).join('\n\n')
      : '（特になし）'
  }
}];

